public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        FenwickTree[] ft = new FenwickTree[6];
        for (int k = 0; k < 6; k++) {
            ft[k] = new FenwickTree(n);
        }

        for (int i = 0; i < n; i++) {
            int d = depths[i];
            if (d >= 0 && d <= 5) {
                ft[d].update(i + 1, 1);
            }
        }

        long[] answer = new long[queries.length];
        int idx = 0;
        for (long[] q : queries) {
            if (q[0] == 1) {
                int l = (int) q[1];
                int r = (int) q[2];
                int k = (int) q[3];
                if (k < 0 || k > 5) {
                    answer[idx++] = 0;
                    continue;
                }
                FenwickTree f = ft[k];
                long sum_r = f.query(r + 1);
                long sum_l_minus_1 = f.query(l);
                answer[idx++] = sum_r - sum_l_minus_1;
            } else {
                int pos = (int) q[1];
                long val = q[2];
                int old_d = depths[pos];
                if (old_d >= 0 && old_d <= 5) {
                    ft[old_d].update(pos + 1, -1);
                }
                nums[pos] = val;
                int new_d = computeDepth(val);
                if (new_d >= 0 && new_d <= 5) {
                    ft[new_d].update(pos + 1, 1);
                }
                depths[pos] = new_d;
            }
        }
        return answer;
    }

    public static class FenwickTree {
        private int size;
        private int[] tree;

        public FenwickTree(int size) {
            this.size = size;
            tree = new int[size + 1]; // 1-based
        }

        public void update(int index, int delta) {
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public int query(int index) {
            int sum = 0;
            while (index > 0) {
                sum += tree[index];
                index -= index & -index;
            }
            return sum;
        }
    }

    public static int computeDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
