public class Solution {
    static class FenwickTree {
        private int size;
        private int[] tree;

        public FenwickTree(int size) {
            this.size = size;
            tree = new int[size + 1]; // 1-based indexing
        }

        public void update(int index, int delta) {
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public int rangeSum(int l, int r) {
            return query(r) - query(l - 1);
        }

        private int query(int index) {
            int sum = 0;
            while (index > 0) {
                sum += tree[index];
                index -= index & -index;
            }
            return sum;
        }
    }

    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        long[] depths = new long[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        FenwickTree[] ft = new FenwickTree[7];
        for (int d = 0; d <= 6; d++) {
            ft[d] = new FenwickTree(n);
        }

        for (int i = 0; i < n; i++) {
            long d = depths[i];
            ft[(int) d].update(i + 1, 1);
        }

        long[] answer = new long[queries.length];
        int idx = 0;
        for (long[] q : queries) {
            if (q[0] == 1) {
                int l = (int) q[1];
                int r = (int) q[2];
                int k = (int) q[3];
                answer[idx++] = ft[k].rangeSum(l + 1, r + 1);
            } else {
                int idxQ = (int) q[1];
                long val = q[2];
                long oldDepth = depths[idxQ];
                long newDepth = computeDepth(val);
                ft[(int) oldDepth].update(idxQ + 1, -1);
                ft[(int) newDepth].update(idxQ + 1, 1);
                depths[idxQ] = newDepth;
                nums[idxQ] = val;
            }
        }

        return answer;
    }

    private static long computeDepth(long x) {
        long depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
}
